const express = require('express');
const AdController = require('../controllers/adController');
const { authenticateToken, requireAdmin } = require('../middleware/auth');

const router = express.Router();

// 用户路由（需要认证）
router.use(authenticateToken);

// 提交广告申请
router.post('/submit', AdController.submitAd);

// 获取用户的广告列表
router.get('/user', AdController.getUserAds);

// 获取活跃广告列表
router.get('/active', AdController.getActiveAds);

// 获取区域内的广告
router.get('/region', AdController.getAdsByRegion);

// 检查广告播放状态
router.get('/:adId/status', AdController.checkAdPlayStatus);

// 激活广告
router.post('/:adId/activate', AdController.activateAd);

// 停用广告
router.post('/:adId/deactivate', AdController.deactivateAd);

// 管理员路由（需要管理员权限）
router.use(requireAdmin);

// 获取待审核广告列表
router.get('/pending', AdController.getPendingAds);

// 审核广告
router.post('/:adId/review', AdController.reviewAd);

module.exports = router;
